import Image from "next/image";

import { getLandingPageContent, type FeatureCardVariant } from "@/lib/landing-page-api";

function FeaturePreview({
  variant,
  image,
}: {
  variant: FeatureCardVariant;
  image: {
    src: string;
    alt: string;
  };
}) {
  if (variant === "selfService") {
    return (
      <div className="relative min-h-65 overflow-hidden bg-[linear-gradient(180deg,#f8fafc_0%,#eef2ff_100%)] sm:min-h-60">
        <Image
          src={image.src}
          alt={image.alt}
          fill
          className="object-cover object-center"
          sizes="(min-width: 1024px) 320px, (min-width: 640px) 50vw, 100vw"
        />
      </div>
    );
  }

  if (variant === "kitchenManagement") {
    return (
      <div className="relative min-h-65 overflow-hidden bg-[linear-gradient(135deg,#f8fafc_0%,#e2e8f0_100%)] sm:min-h-60">
        <Image
          src={image.src}
          alt={image.alt}
          fill
          className="object-cover object-center"
          sizes="(min-width: 1024px) 320px, (min-width: 640px) 50vw, 100vw"
        />
      </div>
    );
  }

  return (
    <div className="relative min-h-65 overflow-hidden bg-[linear-gradient(135deg,#f8fafc_0%,#f3f4f6_100%)] sm:min-h-60">
      <Image
        src={image.src}
        alt={image.alt}
        fill
        className="object-cover object-center"
        sizes="(min-width: 1024px) 320px, (min-width: 640px) 50vw, 100vw"
      />
    </div>
  );
}

export default async function Home() {
  const { hero, featuresSection } = await getLandingPageContent();

  return (
    <div className="min-h-screen w-full bg-slate-50 text-slate-950">
      <div className="mx-auto flex min-h-screen w-full max-w-6xl flex-col px-4 py-12 sm:px-6 lg:px-8">
        <main className="flex flex-1 flex-col gap-16">
          <section className="space-y-10 rounded-4xl border border-slate-200/80 bg-white p-6 shadow-[0_30px_80px_-50px_rgba(15,23,42,0.25)] sm:p-8 lg:p-10">
            <div className="mx-auto max-w-3xl space-y-6 text-center">
              <p className="text-sm font-semibold uppercase tracking-[0.35em] text-slate-400 sm:text-base">
                {hero.eyebrow}
              </p>
              <h1 className="max-w-3xl text-4xl font-semibold tracking-tight text-slate-950 sm:text-5xl lg:text-6xl">
                {hero.title.lineOne}
                <span className="block bg-linear-to-r from-sky-500 via-slate-400 to-amber-400 bg-clip-text text-transparent">
                  {hero.title.lineTwo}
                </span>
              </h1>
              <p className="mx-auto max-w-2xl text-base leading-8 text-slate-600 sm:text-lg">
                {hero.description}
              </p>
              <div className="flex justify-center">
                <a
                  href={hero.primaryAction.href}
                  className="inline-flex min-w-44 items-center justify-center rounded-full bg-gradient-to-r from-sky-500 to-amber-400 px-6 py-3 text-base font-semibold text-white shadow-lg shadow-sky-500/20 transition hover:brightness-110 sm:px-8"
                >
                  {hero.primaryAction.label}
                </a>
              </div>
            </div>

            <div id={featuresSection.id} className="space-y-8">
              <div className="mx-auto max-w-3xl text-center">
                <h2 className="text-2xl font-semibold text-slate-950 sm:text-3xl lg:text-4xl">
                  {featuresSection.title}
                </h2>
                <p className="mt-4 text-sm leading-7 text-slate-500 sm:text-base">
                  {featuresSection.description}
                </p>
              </div>

              <div className="mx-auto h-1 w-24 rounded-full bg-slate-200" />

              <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
                {featuresSection.cards.map((card) => (
                  <article
                    key={card.title}
                    className="rounded-[1.75rem] border border-slate-200 bg-slate-50 p-6 shadow-sm shadow-slate-200/70"
                  >
                    <h3 className="text-lg font-semibold text-slate-950">{card.title}</h3>
                    <div className="mt-6 overflow-hidden rounded-[1.75rem] bg-white shadow-[0_15px_40px_-30px_rgba(15,23,42,0.25)]">
                      <FeaturePreview variant={card.variant} image={card.image} />
                    </div>
                  </article>
                ))}
              </div>

              <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
                <button
                  aria-label={featuresSection.controls.previousLabel}
                  className="flex h-12 w-12 items-center justify-center rounded-full border border-slate-300 bg-white text-slate-700 shadow-sm transition hover:bg-slate-100"
                >
                  ←
                </button>
                <button
                  aria-label={featuresSection.controls.nextLabel}
                  className="flex h-12 w-12 items-center justify-center rounded-full border border-slate-300 bg-white text-slate-700 shadow-sm transition hover:bg-slate-100"
                >
                  →
                </button>
              </div>
            </div>
          </section>
        </main>
      </div>
    </div>
  );
}
